// Pick the best zombie frame for the current walk phase.
// Returns null if frames haven't loaded yet (caller falls back).
function getZombieWalkFrame(phase01, frameCount = 5) {
  // Try to use frame animation
  const idx = Math.floor(phase01 * frameCount) % frameCount;
  return getImage(`zombie_walk_${idx}`);
}

// ============ audio.js ============
let audioCtx = null;
let unlocked = false;

function ensureCtx() {
  if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  if (audioCtx.state === 'suspended') audioCtx.resume();
  return audioCtx;
}
function unlockAudio() {
  if (unlocked) return;
  ensureCtx();
  unlocked = true;
}
function isUnlocked() { return unlocked; }

function envelope(node, t0, attack, decay, peak) {
  const g = node.gain;
  g.cancelScheduledValues(t0);
  g.setValueAtTime(0, t0);
  g.linearRampToValueAtTime(peak, t0 + attack);
  g.exponentialRampToValueAtTime(0.0001, t0 + attack + decay);
}

function tone({ freq, freqEnd, type = 'sine', duration = 0.2, volume = 0.3, attack = 0.01 }) {
  const c = ensureCtx();
  const t0 = c.currentTime;
  const osc = c.createOscillator();
  const gain = c.createGain();
  osc.type = type;
  osc.frequency.setValueAtTime(freq, t0);
  if (freqEnd != null) {
    osc.frequency.exponentialRampToValueAtTime(Math.max(freqEnd, 0.001), t0 + duration);
  }
  envelope(gain, t0, attack, Math.max(duration - attack, 0.05), volume);
  osc.connect(gain).connect(c.destination);
  osc.start(t0);
  osc.stop(t0 + duration + 0.05);
}

function noiseBurst({ duration = 0.2, volume = 0.4, lowpass = 1500 }) {
  const c = ensureCtx();
  const t0 = c.currentTime;
  const buffer = c.createBuffer(1, Math.max(1, Math.floor(c.sampleRate * duration)), c.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
  const src = c.createBufferSource();
  src.buffer = buffer;
  const filter = c.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(lowpass, t0);
  const gain = c.createGain();
  envelope(gain, t0, 0.005, duration, volume);
  src.connect(filter).connect(gain).connect(c.destination);
  src.start(t0);
  src.stop(t0 + duration + 0.05);
}

