// ============ particles.js ============
class Particle {
  constructor(opts) {
    this.x = opts.x;
    this.y = opts.y;
    this.vx = opts.vx || 0;
    this.vy = opts.vy || 0;
    this.gravity = opts.gravity || 0;
    this.r = opts.r || 4;
    this.life = opts.life || 0.5;
    this.color = opts.color || 'rgba(255,255,255,ALPHA)';
    this.shrink = opts.shrink ?? true;
    this.t = 0;
    this.isDead = false;
  }

  update(dt) {
    this.t += dt;
    if (this.t >= this.life) { this.isDead = true; return; }
    this.x += this.vx * dt;
    this.y += this.vy * dt;
    this.vy += this.gravity * dt;
  }

  render(ctx) {
    const alpha = 1 - this.t / this.life;
    ctx.fillStyle = this.color.replace('ALPHA', alpha.toFixed(2));
    const r = this.shrink ? this.r * (1 - this.t / this.life * 0.5) : this.r;
    ctx.beginPath();
    ctx.arc(this.x, this.y, Math.max(0.1, r), 0, Math.PI * 2);
    ctx.fill();
  }
}
class Shockwave {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.t = 0;
    this.life = 0.4;
    this.isDead = false;
  }
  update(dt) {
    this.t += dt;
    if (this.t >= this.life) this.isDead = true;
  }
  render(ctx) {
    const k = this.t / this.life;
    const r = 30 + k * 150;
    ctx.strokeStyle = `rgba(255, 255, 220, ${(1 - k).toFixed(2)})`;
    ctx.lineWidth = 10 * (1 - k);
    ctx.beginPath();
    ctx.arc(this.x, this.y, r, 0, Math.PI * 2);
    ctx.stroke();
    // inner glow
    ctx.fillStyle = `rgba(255, 180, 60, ${(0.4 * (1 - k)).toFixed(2)})`;
    ctx.beginPath();
    ctx.arc(this.x, this.y, r * 0.7, 0, Math.PI * 2);
    ctx.fill();
  }
}
class FloatingText {
  constructor(x, y, text, color = '#fff') {
    this.x = x;
    this.y = y;
    this.text = text;
    this.color = color;
    this.t = 0;
    this.life = 0.5;
    this.isDead = false;
  }
  update(dt) {
    this.t += dt;
    this.y -= 30 * dt;
    if (this.t >= this.life) this.isDead = true;
  }
  render(ctx) {
    const alpha = 1 - this.t / this.life;
    ctx.fillStyle = this.color;
    ctx.globalAlpha = alpha;
    ctx.font = 'bold 16px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(this.text, this.x, this.y);
    ctx.globalAlpha = 1;
  }
}
