// ============ sun.js ============
class Sun {
  constructor(x, y, value, fromSky = true) {
    this.x = x;
    this.y = y;
    this.startX = x;
    this.startY = y;
    this.value = value;
    this.fromSky = fromSky;
    this.fromSunflower = !fromSky;

    if (fromSky) {
      this.vy = 110;
      this.targetY = GRID_Y0 + 20 + Math.random() * (GRID_ROWS * CELL_H - 60);
    } else {
      // sunflower: hop up + gravity drop
      this.vx = (Math.random() * 80 - 40);
      this.vy = -180;
      this.gravity = 500;
      this.targetY = y + 30;
    }

    this.life = SKY_SUN_LIFETIME;
    this.age = 0;
    this.collected = false;
    this.flyTo = null;
    this.flyT = 0;
    this.flyStart = null;
    this.isDead = false;

    // visual
    this.spinT = Math.random() * Math.PI * 2;
  }

  update(dt) {
    this.spinT += dt * 1.5;

    if (this.collected) {
      this.flyT += dt;
      const t = Math.min(this.flyT / 0.5, 1);
      const ease = 1 - (1 - t) * (1 - t);
      this.x = this.flyStart.x + (this.flyTo.x - this.flyStart.x) * ease;
      this.y = this.flyStart.y + (this.flyTo.y - this.flyStart.y) * ease;
      if (t >= 1) this.isDead = true;
      return;
    }

    if (this.fromSunflower) {
      this.x += this.vx * dt;
      this.y += this.vy * dt;
      this.vy += this.gravity * dt;
      if (this.y >= this.targetY) {
        this.y = this.targetY;
        this.vy = 0;
        this.vx = 0;
      }
    } else if (this.y < this.targetY) {
      this.y += this.vy * dt;
      if (this.y > this.targetY) this.y = this.targetY;
    }

    if (this.fromSunflower ? this.vy === 0 : this.y >= this.targetY) {
      this.age += dt;
      if (this.age > this.life) this.isDead = true;
    }
  }

  collect(targetX, targetY) {
    if (this.collected) return;
    this.collected = true;
    this.flyTo = { x: targetX, y: targetY };
    this.flyStart = { x: this.x, y: this.y };
    this.flyT = 0;
  }

  render(ctx) {
    const pulse = 1 + Math.sin(this.spinT * 2) * 0.06;
    const r = 22 * pulse;
    // outer glow
    const glow = ctx.createRadialGradient(this.x, this.y, 8, this.x, this.y, r + 8);
    glow.addColorStop(0, 'rgba(255, 240, 120, 0.5)');
    glow.addColorStop(1, 'rgba(255, 200, 0, 0)');
    ctx.fillStyle = glow;
    ctx.beginPath();
    ctx.arc(this.x, this.y, r + 8, 0, Math.PI * 2);
    ctx.fill();
    // body
    const grad = ctx.createRadialGradient(this.x - 5, this.y - 5, 4, this.x, this.y, r);
    grad.addColorStop(0, '#fff8a3');
    grad.addColorStop(0.6, COLORS.sunGold);
    grad.addColorStop(1, '#e89d00');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(this.x, this.y, r, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = '#a36b00';
    ctx.lineWidth = 1.5;
    ctx.stroke();
    // rays
    ctx.save();
    ctx.translate(this.x, this.y);
    ctx.rotate(this.spinT);
    ctx.strokeStyle = 'rgba(255, 230, 120, 0.7)';
    ctx.lineWidth = 2;
    for (let i = 0; i < 8; i++) {
      ctx.rotate(Math.PI / 4);
      ctx.beginPath();
      ctx.moveTo(r + 2, 0);
      ctx.lineTo(r + 6, 0);
      ctx.stroke();
    }
    ctx.restore();
  }

  hitTest(px, py) {
    const dx = px - this.x;
    const dy = py - this.y;
    return dx * dx + dy * dy <= 32 * 32;
  }
}
function spawnSkySun(game) {
  const x = GRID_X0 + 20 + Math.random() * (GRID_COLS * CELL_W - 40);
  game.suns.push(new Sun(x, -20, SKY_SUN_VALUE, true));
}

// ============ projectiles.js ============
class Pea {
  constructor(x, row, snow = false) {
    this.x = x;
    this.row = row;
    this.y = rowToY(row) - 30;
    this.snow = snow;
    this.dmg = PEA_DAMAGE;
    this.isDead = false;
    this.trail = [];
  }

  update(dt, game) {
    this.trail.push({ x: this.x, y: this.y, life: 0.18 });
    for (const t of this.trail) t.life -= dt;
    this.trail = this.trail.filter(t => t.life > 0);

    this.x += PROJECTILE_SPEED * dt;
    if (this.x > CANVAS_W + 20) { this.isDead = true; return; }

    for (const z of game.zombies) {
      if (z.row !== this.row || z.isDead || z.state === 'dying') continue;
      if (this.x >= z.getFrontX() && this.x <= z.x + 12) {
        z.takeDamage(this.dmg);
        if (this.snow) z.applySlow(SNOW_PEA_SLOW_DURATION);
        spawnHit(game, this.x, this.y, this.snow);
        play(this.snow ? 'iceHit' : 'hit');
        this.isDead = true;
        return;
      }
    }
  }

  render(ctx) {
    for (const t of this.trail) {
      const a = (t.life / 0.18).toFixed(2);
      ctx.fillStyle = this.snow ? `rgba(159,211,232,${a})` : `rgba(180, 240, 130, ${a})`;
      ctx.beginPath();
      ctx.arc(t.x, t.y, 5 * (t.life / 0.18), 0, Math.PI * 2);
      ctx.fill();
    }
    const grad = ctx.createRadialGradient(this.x - 2, this.y - 2, 1, this.x, this.y, 7);
    if (this.snow) {
      grad.addColorStop(0, '#ffffff');
      grad.addColorStop(1, '#7fc3e0');
    } else {
      grad.addColorStop(0, '#dffbb0');
      grad.addColorStop(1, '#5fa830');
    }
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(this.x, this.y, 7, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = this.snow ? '#3a6a80' : '#2e6a18';
    ctx.lineWidth = 1.2;
    ctx.stroke();
  }
}

// ============ zombies.js ============
class Zombie {
  constructor(type, row) {
    this.type = type;
    this.cfg = ZOMBIES[type];
    this.hp = this.cfg.hp;
    this.accessoryHpMax = this.cfg.accessoryHp || 0;
    this.accessoryHp = this.accessoryHpMax;
    this.row = row;
    this.gridX = GRID_COLS;
    this.x = gridXToPixel(this.gridX);
    this.y = rowToY(row);
    this.speed = this.cfg.speed;
    this.state = 'walking';
    this.biteTimer = 0;
    this.target = null;
    this.slowT = 0;
    this.dyingT = 0;
    this.spawnFade = 0;
    this.legPhase = Math.random() * Math.PI * 2;
    this.armPhase = Math.random() * Math.PI * 2;
    this.isDead = false;
    play('zombieMoan');
  }

  update(dt, game) {
    this.spawnFade = Math.min(this.spawnFade + dt * 2, 1);
    if (this.slowT > 0) this.slowT -= dt;

    if (this.state === 'dying') {
      this.dyingT += dt;
      if (this.dyingT > 0.6) this.isDead = true;
      return;
    }

    if (this.hp <= 0) {
      this.state = 'dying';
      spawnZombieDeathSoul(game, this.x, this.y);
      return;
    }

    const slow = this.slowT > 0 ? 0.5 : 1;

    if (this.state === 'walking') {
      this.gridX -= (this.speed * slow / 80) * dt;
      this.x = gridXToPixel(this.gridX);
      this.legPhase += dt * 5 * slow;
      const target = findTargetPlant(game, this);
      if (target) {
        this.state = 'eating';
        this.target = target;
        this.biteTimer = 0;
      }
    } else if (this.state === 'eating') {
      if (!this.target || this.target.isDead || !sameCell(this.target, this)) {
        this.state = 'walking';
        this.target = null;
        return;
      }
      this.armPhase += dt * 8;
      this.biteTimer += dt;
      if (this.biteTimer >= this.cfg.biteInterval) {
        this.biteTimer = 0;
        this.target.takeDamage(this.cfg.biteDamage);
        play('bite');
      }
    }
  }

  takeDamage(dmg) {
    if (this.accessoryHp > 0) {
      const used = Math.min(this.accessoryHp, dmg);
      this.accessoryHp -= used;
      dmg -= used;
    }
    if (dmg > 0) this.hp -= dmg;
  }

  applySlow(seconds) {
    this.slowT = Math.max(this.slowT, seconds);
  }

  getFrontX() {
    return this.x - 14;
  }

  render(ctx) {
    ctx.save();
    ctx.globalAlpha = this.spawnFade;
    if (this.state === 'dying') {
      const k = this.dyingT / 0.6;
      ctx.translate(this.x, this.y);
      ctx.rotate(k * Math.PI / 2.2);
      ctx.globalAlpha *= (1 - k);
      this.draw(ctx);
      ctx.restore();
      return;
    }
    ctx.translate(this.x, this.y);
    this.draw(ctx);
    if (this.slowT > 0) {
      ctx.globalCompositeOperation = 'source-atop';
      ctx.fillStyle = 'rgba(120, 200, 240, 0.45)';
      ctx.fillRect(-30, -100, 60, 110);
      ctx.globalCompositeOperation = 'source-over';
    }
    ctx.restore();
  }

  draw(ctx) {
    // Prefer frame-based walk animation if frames are loaded, otherwise
    // fall back to single static image, otherwise canvas drawing.
    const phase01 = ((this.legPhase / (Math.PI * 2)) % 1 + 1) % 1;
    const eating = this.state === 'eating';
    // When eating, lock to a single mid-stride frame so the zombie stops walking
    const walkFrame = getZombieWalkFrame(eating ? 0.4 : phase01);

    if (walkFrame) {
      drawZombieFrame(ctx, walkFrame, this, eating);
    } else {
      const staticImg = getImage('zombie_basic');
      if (staticImg) {
        drawZombieImage(ctx, staticImg, this);
      } else {
        drawBasicZombieBody(ctx, this);
      }
    }

    if (this.type === 'cone') drawCone(ctx, this.accessoryHp, this.accessoryHpMax);
    if (this.type === 'bucket') drawBucket(ctx, this.accessoryHp, this.accessoryHpMax);
  }
}

// Draws a frame of the zombie walk-cycle sprite sheet.
// Frames already encode pose; we add only minimal extra polish:
// - When eating, head-shake jitter to simulate biting
// - Otherwise no extra distortion (the frames carry the animation themselves)
function drawZombieFrame(ctx, img, z, eating) {
  const W = 95;
  const H = 130;
  let dx = 0, dy = 0, tilt = 0;
  if (eating) {
    dx = Math.sin(z.legPhase * 8) * 1.2;
    dy = Math.sin(z.legPhase * 4) * 1.5;
    tilt = -0.04;  // slight forward lean
  }
  ctx.save();
  if (tilt) ctx.rotate(tilt);
  // Anchor at bottom-center: feet roughly at y=14, head extends up to y≈-116
  ctx.drawImage(img, -W / 2 + dx, -H + 14 + dy, W, H);
  ctx.restore();
}

// Renders the zombie body image with a layered shambling-walk animation.
// We only have one frame, so we fake walking via:
//   1. Vertical bob (body rises mid-stride, drops on foot-strike)
//   2. Alternating tilt (body leans left/right with each step)
//   3. Foot-strike squash (vertical compression on impact for weight)
//   4. Asymmetric drift (zombies don't walk straight — slight wobble)
//   5. Idle micro-sway when eating, with head-shake from biting
function drawZombieImage(ctx, img, z) {
  const W = 90;
  const H = 130;
  const eating = z.state === 'eating';
  const phase = z.legPhase;

  let bobY, tilt, squashY, dx;

  if (eating) {
    // Eating: forward lean + small head-shake bobbing rhythm
    bobY = Math.sin(phase * 5) * 2;
    tilt = -0.06 + Math.sin(phase * 6) * 0.015;  // lean forward (left)
    squashY = 1;
    dx = Math.sin(phase * 6) * 1.2;
  } else {
    // Walking shamble:
    // - sin(phase) gives one full gait cycle (2 steps) per 2π
    // - abs(sin(phase * 2)) gives the up-down lift each step (peaks at mid-stride)
    const stride = Math.abs(Math.sin(phase));            // 0..1, one bump per step
    const sideTilt = Math.sin(phase * 0.5);              // -1..1, alternates each gait cycle
    bobY = -stride * 5;                                  // body lifts up while in stride
    tilt = sideTilt * 0.07 - 0.02;                       // ±4 deg lean, slight forward bias
    squashY = 1 - (1 - stride) * 0.05;                   // squash 5% at foot-strike (stride=0)
    dx = Math.cos(phase * 0.5) * 1.5;                    // gentle side-to-side drift
  }

  ctx.save();
  ctx.translate(dx, 0);
  ctx.rotate(tilt);
  ctx.scale(1, squashY);
  // Anchor: feet at y≈14, head up to y≈-116
  ctx.drawImage(img, -W / 2, -H + 14 + bobY, W, H);
  ctx.restore();
}

function drawBasicZombieBody(ctx, z) {
  const eating = z.state === 'eating';
  const legSwing = Math.sin(z.legPhase) * 5;
  // legs
  ctx.fillStyle = '#5a6a3a';
  ctx.fillRect(-10 + legSwing, -10, 8, 20);
  ctx.fillStyle = '#4a5a2a';
  ctx.fillRect(2 - legSwing, -10, 8, 20);
  // shoes
  ctx.fillStyle = '#2a1a08';
  ctx.fillRect(-12 + legSwing, 8, 11, 4);
  ctx.fillRect(0 - legSwing, 8, 11, 4);
  // body / shirt
  ctx.fillStyle = '#7a8a5a';
  ctx.fillRect(-15, -45, 30, 38);
  // shirt details (tattered)
  ctx.fillStyle = '#3d4a2a';
  ctx.beginPath();
  ctx.moveTo(-15, -28); ctx.lineTo(-10, -22);
  ctx.lineTo(-4, -28); ctx.lineTo(2, -22);
  ctx.lineTo(8, -28); ctx.lineTo(15, -22);
  ctx.lineTo(15, -8); ctx.lineTo(-15, -8);
  ctx.closePath();
  ctx.fill();
  // shirt collar
  ctx.fillStyle = '#3d4a2a';
  ctx.beginPath();
  ctx.moveTo(-15, -45);
  ctx.lineTo(-8, -41); ctx.lineTo(-2, -45); ctx.lineTo(4, -41); ctx.lineTo(10, -45); ctx.lineTo(15, -41);
  ctx.lineTo(15, -34); ctx.lineTo(-15, -34);
  ctx.closePath();
  ctx.fill();
  // arms reaching forward
  const armReach = eating ? Math.sin(z.armPhase) * 4 : 0;
  ctx.fillStyle = '#a8b888';
  ctx.fillRect(-26 - armReach, -40, 12, 6);
  ctx.fillRect(-30 - armReach, -36, 6, 6);
  ctx.fillRect(-26 - armReach, -34, 12, 6);
  // tie
  ctx.fillStyle = '#7c2222';
  ctx.beginPath();
  ctx.moveTo(0, -34); ctx.lineTo(-4, -28); ctx.lineTo(0, -16); ctx.lineTo(4, -28);
  ctx.closePath();
  ctx.fill();
  // head
  const headBob = eating ? Math.sin(z.legPhase * 4) * 2 : Math.sin(z.legPhase) * 1;
  ctx.save();
  ctx.translate(-2, -55 + headBob);
  ctx.rotate(-0.08);
  // neck
  ctx.fillStyle = '#5a6a3a';
  ctx.fillRect(-4, 6, 8, 6);
  // skull
  ctx.fillStyle = '#a8b888';
  ctx.beginPath();
  ctx.ellipse(0, 0, 15, 17, 0, 0, Math.PI * 2);
  ctx.fill();
  // hair tuft
  ctx.fillStyle = '#3d2410';
  ctx.beginPath();
  ctx.moveTo(-12, -10); ctx.lineTo(-8, -16); ctx.lineTo(-2, -12);
  ctx.lineTo(4, -16); ctx.lineTo(10, -10); ctx.lineTo(8, -6); ctx.lineTo(-10, -6);
  ctx.closePath();
  ctx.fill();
  // eyes
  ctx.fillStyle = '#fff';
  ctx.beginPath(); ctx.arc(-5, -2, 3, 0, Math.PI * 2); ctx.fill();
  ctx.beginPath(); ctx.arc(4, -2, 3, 0, Math.PI * 2); ctx.fill();
  ctx.fillStyle = '#000';
  ctx.beginPath(); ctx.arc(-4, -1, 1.5, 0, Math.PI * 2); ctx.fill();
  ctx.beginPath(); ctx.arc(5, -1, 1.5, 0, Math.PI * 2); ctx.fill();
  // mouth
  ctx.strokeStyle = '#3d2410';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  if (eating) {
    ctx.moveTo(-7, 8); ctx.lineTo(-3, 11); ctx.lineTo(0, 8); ctx.lineTo(3, 11); ctx.lineTo(7, 8);
  } else {
    ctx.moveTo(-7, 9); ctx.lineTo(7, 9);
  }
  ctx.stroke();
  // teeth hint
  ctx.fillStyle = '#fff';
  ctx.fillRect(-2, 8, 2, 2);
  ctx.fillRect(2, 8, 2, 2);
  ctx.restore();
}

function drawCone(ctx, accessoryHp, maxHp) {
  const stage = accessoryHp > maxHp * 2 / 3 ? 0 : accessoryHp > maxHp / 3 ? 1 : 2;
  ctx.save();
  ctx.translate(-2, -68);
  // cone body
  const grad = ctx.createLinearGradient(-14, 12, 14, -22);
  grad.addColorStop(0, '#c66010');
  grad.addColorStop(0.5, '#e88830');
  grad.addColorStop(1, '#a04808');
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.moveTo(-14, 12);
  ctx.lineTo(14, 12);
  ctx.lineTo(2, -22);
  ctx.lineTo(-2, -22);
  ctx.closePath();
  ctx.fill();
  // stripes
  ctx.strokeStyle = 'rgba(255,255,255,0.4)';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(-12, 4); ctx.lineTo(12, 4);
  ctx.moveTo(-9, -4); ctx.lineTo(9, -4);
  ctx.moveTo(-5, -12); ctx.lineTo(5, -12);
  ctx.stroke();
  // damage stages
  if (stage >= 1) {
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(2, -22); ctx.lineTo(-3, -16); ctx.lineTo(3, -10);
    ctx.stroke();
  }
  if (stage >= 2) {
    ctx.fillStyle = '#000';
    ctx.beginPath(); ctx.arc(-5, 0, 2.5, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(7, 6, 2, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#5a3018';
    ctx.beginPath();
    ctx.moveTo(-14, 12); ctx.lineTo(-12, 6); ctx.lineTo(-9, 12); ctx.fill();
  }
  ctx.restore();
}

function drawBucket(ctx, accessoryHp, maxHp) {
  const stage = accessoryHp > maxHp * 2 / 3 ? 0 : accessoryHp > maxHp / 3 ? 1 : 2;
  ctx.save();
  ctx.translate(-2, -76);
  // body
  const grad = ctx.createLinearGradient(-15, 18, 15, -8);
  grad.addColorStop(0, '#6a6a6a');
  grad.addColorStop(0.5, '#a8a8a8');
  grad.addColorStop(1, '#7a7a7a');
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.moveTo(-15, 18);
  ctx.lineTo(15, 18);
  ctx.lineTo(13, -8);
  ctx.lineTo(-13, -8);
  ctx.closePath();
  ctx.fill();
  // top rim
  ctx.fillStyle = '#5a5a5a';
  ctx.fillRect(-15, -10, 30, 4);
  // rivets
  ctx.fillStyle = '#3a3a3a';
  ctx.beginPath(); ctx.arc(-11, -2, 1.5, 0, Math.PI * 2); ctx.fill();
  ctx.beginPath(); ctx.arc(11, -2, 1.5, 0, Math.PI * 2); ctx.fill();
  ctx.beginPath(); ctx.arc(-11, 12, 1.5, 0, Math.PI * 2); ctx.fill();
  ctx.beginPath(); ctx.arc(11, 12, 1.5, 0, Math.PI * 2); ctx.fill();
  // stage damage
  if (stage >= 1) {
    ctx.fillStyle = '#3a3a3a';
    ctx.beginPath();
    ctx.moveTo(-7, 12); ctx.lineTo(0, 4); ctx.lineTo(5, 12); ctx.fill();
  }
  if (stage >= 2) {
    ctx.fillStyle = '#7a4a1a';
    ctx.beginPath(); ctx.arc(-8, 5, 3, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(7, 14, 3, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#3a3a3a';
    ctx.beginPath();
    ctx.moveTo(13, -8); ctx.lineTo(10, -4); ctx.lineTo(13, 0); ctx.fill();
  }
  ctx.restore();
}

function sameCell(plant, zombie) {
  if (plant.row !== zombie.row) return false;
  return Math.abs(zombie.x - plant.x) < 32;
}

function findTargetPlant(game, zombie) {
  for (const p of game.plants) {
    if (p.row !== zombie.row || p.isDead) continue;
    if (zombie.x - 14 < p.x + 24 && zombie.x + 6 > p.x - 24) {
      return p;
    }
  }
  return null;
}
function createZombie(type, row) {
  return new Zombie(type, row);
}

// ============ mower.js ============
class Mower {
  constructor(row) {
    this.row = row;
    this.x = GRID_X0 - 28;
    this.y = rowToY(row);
    this.state = 'idle';
    this.speed = 0;
    this.bladePhase = 0;
    this.isDead = false;
  }

  update(dt, game) {
    if (this.state === 'idle') {
      for (const z of game.zombies) {
        if (z.row !== this.row || z.state === 'dying') continue;
        if (z.x <= GRID_X0 + 50) {
          this.state = 'running';
          this.speed = 80;
          play('mower');
          break;
        }
      }
    } else if (this.state === 'running') {
      this.speed = Math.min(this.speed + 1000 * dt, 700);
      this.x += this.speed * dt;
      this.bladePhase += dt * 25;
      for (const z of game.zombies) {
        if (z.row !== this.row || z.state === 'dying') continue;
        if (Math.abs(z.x - this.x) < 30) {
          z.hp = -9999;
          z.accessoryHp = 0;
        }
      }
      if (this.x > 1100) {
        this.state = 'done';
        this.isDead = true;
      }
    }
  }

  render(ctx) {
    ctx.save();
    ctx.translate(this.x, this.y + 22);
    // body
    const grad = ctx.createLinearGradient(0, -16, 0, 8);
    grad.addColorStop(0, '#e44');
    grad.addColorStop(1, '#a22');
    ctx.fillStyle = grad;
    ctx.fillRect(-22, -14, 44, 18);
    // top stripe
    ctx.fillStyle = '#fff';
    ctx.fillRect(-22, -10, 44, 2);
    ctx.fillStyle = '#000';
    ctx.font = 'bold 9px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('MOWER', 0, -1);
    // wheels
    ctx.fillStyle = '#222';
    ctx.beginPath(); ctx.arc(-14, 6, 7, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(14, 6, 7, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#666';
    ctx.beginPath(); ctx.arc(-14, 6, 3, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(14, 6, 3, 0, Math.PI * 2); ctx.fill();
    // blade (spinning when running)
    ctx.save();
    ctx.translate(-26, -2);
    if (this.state === 'running') {
      ctx.rotate(this.bladePhase);
      ctx.fillStyle = 'rgba(200,200,200,0.5)';
      for (let i = 0; i < 4; i++) {
        ctx.rotate(Math.PI / 2);
        ctx.fillRect(-1, -10, 2, 20);
      }
    } else {
      ctx.fillStyle = '#999';
      ctx.fillRect(-3, -8, 6, 16);
    }
    ctx.restore();
    // handle
    ctx.strokeStyle = '#222';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(15, -14); ctx.lineTo(28, -28);
    ctx.stroke();
    ctx.restore();
  }
}
function spawnMowers(game) {
  for (let r = 0; r < GRID_ROWS; r++) game.mowers.push(new Mower(r));
}

// ============ plants.js ============
function easeOut(t) { return 1 - (1 - t) * (1 - t); }
class Plant {
  constructor(id, col, row) {
    this.id = id;
    this.cfg = PLANTS[id];
    this.col = col;
    this.row = row;
    this.x = colToX(col);
    this.y = rowToY(row);
    this.hp = this.cfg.hp;
    this.maxHp = this.cfg.hp;
    this.spawnT = 0;
    this.lifetime = 0;
    this.shake = 0;
    this.isDead = false;
  }

  update(dt, game) {
    this.spawnT = Math.min(this.spawnT + dt * 3.5, 1);
    this.lifetime += dt;
    if (this.shake > 0) this.shake -= dt;
    if (this.hp <= 0) this.isDead = true;
  }

  takeDamage(dmg) {
    this.hp -= dmg;
    this.shake = 0.15;
  }

  render(ctx) {
    const scale = 0.3 + 0.7 * easeOut(this.spawnT);
    const shakeX = this.shake > 0 ? (Math.random() * 4 - 2) : 0;
    ctx.save();
    ctx.translate(this.x + shakeX, this.y + 18);
    ctx.scale(scale, scale);
    this.draw(ctx);
    ctx.restore();
  }

  draw(ctx) { /* override */ }
}
class Sunflower extends Plant {
  constructor(col, row) {
    super('sunflower', col, row);
    this.cycle = SUNFLOWER_INTERVAL * 0.55;
    this.pulse = 0;
    this.bob = Math.random() * Math.PI * 2;
  }

  update(dt, game) {
    super.update(dt, game);
    this.bob += dt * 1.5;
    this.cycle -= dt;
    this.pulse = Math.max(this.pulse - dt * 2.5, 0);
    if (this.cycle <= 0) {
      this.cycle = SUNFLOWER_INTERVAL;
      this.pulse = 1;
      game.suns.push(new Sun(this.x + (Math.random() * 20 - 10), this.y - 10, SUNFLOWER_SUN_VALUE, false));
    }
  }

  draw(ctx) {
    const img = getImage('sunflower');
    if (img) {
      drawSunflowerImage(ctx, img, this);
      return;
    }
    const sway = Math.sin(this.bob) * 0.05;
    ctx.save();
    ctx.rotate(sway);
    // stem
    ctx.fillStyle = '#3a8b3a';
    ctx.fillRect(-4, -8, 8, 30);
    // leaves
    ctx.fillStyle = '#4eaa4e';
    ctx.beginPath();
    ctx.ellipse(-12, 8, 10, 5, -0.3, 0, Math.PI * 2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(12, 14, 10, 5, 0.3, 0, Math.PI * 2);
    ctx.fill();
    // petals
    const pulseScale = 1 + this.pulse * 0.18;
    ctx.save();
    ctx.translate(0, -22);
    ctx.scale(pulseScale, pulseScale);
    ctx.fillStyle = '#ffd24a';
    for (let i = 0; i < 12; i++) {
      const a = i * Math.PI / 6;
      ctx.save();
      ctx.rotate(a);
      const grad = ctx.createLinearGradient(0, -8, 0, -22);
      grad.addColorStop(0, '#ffe580');
      grad.addColorStop(1, '#f6a800');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.ellipse(0, -18, 7, 14, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    }
    // center
    const centerGrad = ctx.createRadialGradient(-3, -3, 2, 0, 0, 14);
    centerGrad.addColorStop(0, '#a06a30');
    centerGrad.addColorStop(1, '#5a3010');
    ctx.fillStyle = centerGrad;
    ctx.beginPath();
    ctx.arc(0, 0, 13, 0, Math.PI * 2);
    ctx.fill();
    // seeds dots
    ctx.fillStyle = '#3a1a08';
    for (let i = 0; i < 8; i++) {
      const a = i * Math.PI / 4;
      ctx.beginPath();
      ctx.arc(Math.cos(a) * 6, Math.sin(a) * 6, 1.5, 0, Math.PI * 2);
      ctx.fill();
    }
    // smile
    ctx.strokeStyle = '#3a1a08';
    ctx.lineWidth = 1.2;
    ctx.beginPath();
    ctx.arc(0, 2, 4, 0.2, Math.PI - 0.2);
    ctx.stroke();
    ctx.restore();
    ctx.restore();
  }
}
class Peashooter extends Plant {
  constructor(col, row) {
    super('peashooter', col, row);
    this.fireT = 0;
    this.firing = 0;
    this.bob = Math.random() * Math.PI * 2;
  }

  update(dt, game) {
    super.update(dt, game);
    this.bob += dt * 1.5;
    this.firing = Math.max(0, this.firing - dt * 6);
    const hasZombie = game.zombies.some(z =>
      z.row === this.row && z.state !== 'dying' && z.x > this.x);
    if (hasZombie) {
      this.fireT += dt;
      if (this.fireT >= PEASHOOTER_FIRE_INTERVAL) {
        this.fireT = 0;
        this.firing = 1;
        game.projectiles.push(new Pea(this.x + 10, this.row, false));
        play('shoot');
      }
    } else {
      this.fireT = Math.min(this.fireT + dt, PEASHOOTER_FIRE_INTERVAL);
    }
  }

  draw(ctx) {
    const img = getImage('peashooter');
    if (img) {
      drawPlantImage(ctx, img, this);
    } else {
      drawShooterBody(ctx, this, '#3eaa3e', '#2a7a2a', false);
    }
  }
}

// Draws a plant image anchored at bottom-center of the cell.
// Adds a subtle bob and a small "punch" forward when firing.
function drawPlantImage(ctx, img, plant) {
  const sway = Math.sin(plant.bob || 0) * 0.04;
  const punch = (plant.firing || 0) * 4;   // shifts right when firing
  const W = 80;
  const H = 90;
  ctx.save();
  ctx.rotate(sway);
  ctx.drawImage(img, -W / 2 + punch, -H + 16, W, H);
  ctx.restore();
}

// Sunflower has a pulse animation when producing a sun.
function drawSunflowerImage(ctx, img, plant) {
  const sway = Math.sin(plant.bob) * 0.04;
  const pulse = 1 + plant.pulse * 0.18;
  const W = 78;
  const H = 92;
  ctx.save();
  ctx.rotate(sway);
  ctx.scale(pulse, pulse);
  ctx.drawImage(img, -W / 2, -H + 16, W, H);
  ctx.restore();
}
class SnowPea extends Plant {
  constructor(col, row) {
    super('snowpea', col, row);
    this.fireT = 0;
    this.firing = 0;
    this.bob = Math.random() * Math.PI * 2;
  }

  update(dt, game) {
    super.update(dt, game);
    this.bob += dt * 1.5;
    this.firing = Math.max(0, this.firing - dt * 6);
    const hasZombie = game.zombies.some(z =>
      z.row === this.row && z.state !== 'dying' && z.x > this.x);
    if (hasZombie) {
      this.fireT += dt;
      if (this.fireT >= PEASHOOTER_FIRE_INTERVAL) {
        this.fireT = 0;
        this.firing = 1;
        game.projectiles.push(new Pea(this.x + 10, this.row, true));
        play('shoot');
      }
    } else {
      this.fireT = Math.min(this.fireT + dt, PEASHOOTER_FIRE_INTERVAL);
    }
  }

  draw(ctx) {
    drawShooterBody(ctx, this, '#9fd3e8', '#5fa3c5', true);
  }
}

function drawShooterBody(ctx, plant, mainColor, darkColor, snow) {
  const sway = Math.sin(plant.bob) * 0.04;
  ctx.save();
  ctx.rotate(sway);
  // stem
  ctx.fillStyle = '#3a8b3a';
  ctx.fillRect(-4, -8, 8, 30);
  // leaves
  ctx.fillStyle = '#4eaa4e';
  ctx.beginPath();
  ctx.ellipse(-12, 12, 10, 5, -0.3, 0, Math.PI * 2);
  ctx.fill();
  ctx.beginPath();
  ctx.ellipse(12, 18, 10, 5, 0.3, 0, Math.PI * 2);
  ctx.fill();
  // head
  ctx.save();
  ctx.translate(0, -20);
  const grad = ctx.createRadialGradient(-5, -7, 3, 0, 0, 20);
  grad.addColorStop(0, snow ? '#ffffff' : '#7eda7e');
  grad.addColorStop(1, mainColor);
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(0, 0, 20, 0, Math.PI * 2);
  ctx.fill();
  // top accent
  ctx.fillStyle = darkColor;
  ctx.beginPath();
  ctx.arc(0, -2, 14, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = mainColor;
  ctx.beginPath();
  ctx.arc(-3, -5, 8, 0, Math.PI * 2);
  ctx.fill();
  // mouth (firing animation)
  ctx.fillStyle = '#000';
  ctx.beginPath();
  if (plant.firing > 0.5) ctx.ellipse(13, 0, 6, 6, 0, 0, Math.PI * 2);
  else ctx.ellipse(13, 0, 5, 1.8, 0, 0, Math.PI * 2);
  ctx.fill();
  // muzzle
  ctx.fillStyle = darkColor;
  ctx.fillRect(11, -4, 4, 8);
  // eye
  ctx.fillStyle = '#fff';
  ctx.beginPath(); ctx.arc(-3, -3, 5, 0, Math.PI * 2); ctx.fill();
  ctx.fillStyle = '#000';
  ctx.beginPath(); ctx.arc(-3, -2, 2.5, 0, Math.PI * 2); ctx.fill();
  ctx.fillStyle = '#fff';
  ctx.beginPath(); ctx.arc(-2, -3, 1, 0, Math.PI * 2); ctx.fill();

  if (snow) {
    // snowflake on forehead
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 1.5;
    for (let i = 0; i < 6; i++) {
      ctx.save();
      ctx.translate(-10, -8);
      ctx.rotate(i * Math.PI / 3);
      ctx.beginPath();
      ctx.moveTo(0, 0); ctx.lineTo(0, -5);
      ctx.stroke();
      ctx.restore();
    }
  }
  ctx.restore();
  ctx.restore();
}
class Wallnut extends Plant {
  constructor(col, row) {
    super('wallnut', col, row);
  }
  draw(ctx) {
    const stage = this.hp > this.maxHp * 2 / 3 ? 0 : this.hp > this.maxHp / 3 ? 1 : 2;
    // body
    const grad = ctx.createRadialGradient(-6, -28, 4, 0, -22, 30);
    grad.addColorStop(0, '#c89060');
    grad.addColorStop(0.6, '#a06a3a');
    grad.addColorStop(1, '#6a3a18');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.ellipse(0, -22, 26, 32, 0, 0, Math.PI * 2);
    ctx.fill();
    // shell texture
    ctx.fillStyle = '#7a4a2a';
    ctx.beginPath();
    ctx.ellipse(-10, -28, 8, 4, -0.3, 0, Math.PI * 2);
    ctx.fill();
    ctx.beginPath();
    ctx.ellipse(8, -16, 7, 3, 0.4, 0, Math.PI * 2);
    ctx.fill();
    // eyes
    ctx.fillStyle = '#fff';
    ctx.beginPath(); ctx.arc(-7, -22, 5, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(7, -22, 5, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#000';
    const eyeOffset = stage === 2 ? 1 : 0;
    ctx.beginPath(); ctx.arc(-7 + eyeOffset, -22, 2.5, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(7 + eyeOffset, -22, 2.5, 0, Math.PI * 2); ctx.fill();
    // mouth
    ctx.strokeStyle = '#3a1a08';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    if (stage === 0) {
      ctx.arc(0, -12, 4, 0, Math.PI);
    } else {
      ctx.moveTo(-5, -10);
      ctx.lineTo(-2, -13);
      ctx.lineTo(2, -10);
      ctx.lineTo(5, -13);
    }
    ctx.stroke();
    // cracks
    if (stage >= 1) {
      ctx.strokeStyle = '#3d1a08';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-15, -38); ctx.lineTo(-10, -32); ctx.lineTo(-15, -25);
      ctx.moveTo(12, -8); ctx.lineTo(6, -14); ctx.lineTo(12, -20);
      ctx.stroke();
    }
    if (stage >= 2) {
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-20, -10); ctx.lineTo(-5, -22); ctx.lineTo(-8, -38);
      ctx.moveTo(18, -28); ctx.lineTo(8, -22); ctx.lineTo(15, -10);
      ctx.stroke();
    }
  }
}
class CherryBomb extends Plant {
  constructor(col, row) {
    super('cherrybomb', col, row);
    this.fuse = CHERRY_FUSE;
    this.exploded = false;
  }

  update(dt, game) {
    super.update(dt, game);
    if (this.exploded) return;
    this.fuse -= dt;
    // sparks every now and then
    if (Math.random() < dt * 8) {
      game.particles.push({
        x: this.x + (Math.random() * 30 - 15),
        y: this.y - 30 + (Math.random() * 10 - 5),
        vx: (Math.random() * 60 - 30),
        vy: -60 - Math.random() * 40,
        gravity: 200,
        r: 2,
        life: 0.3,
        t: 0,
        isDead: false,
        update(dt) {
          this.t += dt;
          if (this.t >= this.life) this.isDead = true;
          this.x += this.vx * dt;
          this.y += this.vy * dt;
          this.vy += this.gravity * dt;
        },
        render(ctx) {
          const a = 1 - this.t / this.life;
          ctx.fillStyle = `rgba(255, 220, 80, ${a.toFixed(2)})`;
          ctx.beginPath();
          ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
          ctx.fill();
        },
      });
    }
    if (this.fuse <= 0) this.explode(game);
  }

  explode(game) {
    this.exploded = true;
    play('explode');
    spawnExplosion(game, this.x, this.y - 20);
    for (const z of game.zombies) {
      if (z.state === 'dying') continue;
      if (Math.abs(z.row - this.row) <= EXPLOSION_RADIUS_COLS &&
          Math.abs((z.x - this.x) / 80) <= EXPLOSION_RADIUS_COLS + 0.5) {
        z.hp = -9999;
        z.accessoryHp = 0;
      }
    }
    this.isDead = true;
  }

  draw(ctx) {
    const flicker = Math.sin(this.lifetime * 30) * 0.5 + 0.5;
    const r = Math.max(0, 1 - this.fuse / CHERRY_FUSE);
    const swell = 1 + r * 0.3;
    ctx.save();
    ctx.scale(swell, swell);
    // stem connector
    ctx.fillStyle = '#3a8b3a';
    ctx.fillRect(-3, -32, 6, 14);
    ctx.beginPath();
    ctx.moveTo(-3, -32); ctx.lineTo(-12, -38); ctx.lineTo(-3, -28); ctx.fill();
    ctx.beginPath();
    ctx.moveTo(3, -32); ctx.lineTo(12, -38); ctx.lineTo(3, -28); ctx.fill();
    // two cherries
    const red = `rgb(${200 + flicker * 55 | 0}, ${20 + flicker * 30 | 0}, ${30})`;
    ctx.fillStyle = red;
    ctx.beginPath(); ctx.arc(-12, -12, 18, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(12, -12, 18, 0, Math.PI * 2); ctx.fill();
    // shading
    ctx.fillStyle = 'rgba(0,0,0,0.25)';
    ctx.beginPath(); ctx.arc(-12, -8, 18, 0.2 * Math.PI, 0.8 * Math.PI); ctx.fill();
    ctx.beginPath(); ctx.arc(12, -8, 18, 0.2 * Math.PI, 0.8 * Math.PI); ctx.fill();
    // highlights
    ctx.fillStyle = 'rgba(255,255,255,0.55)';
    ctx.beginPath(); ctx.arc(-17, -18, 4, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(7, -18, 4, 0, Math.PI * 2); ctx.fill();
    // angry eyes
    ctx.fillStyle = '#fff';
    ctx.beginPath(); ctx.arc(-12, -12, 4, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(12, -12, 4, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#000';
    ctx.beginPath(); ctx.arc(-12, -12, 2, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(12, -12, 2, 0, Math.PI * 2); ctx.fill();
    // angry brows
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(-18, -20); ctx.lineTo(-7, -16);
    ctx.moveTo(7, -16); ctx.lineTo(18, -20);
    ctx.stroke();
    ctx.restore();
  }
}
class PotatoMine extends Plant {
  constructor(col, row) {
    super('potatomine', col, row);
    this.armT = POTATO_ARM_TIME;
    this.armed = false;
    this.exploded = false;
  }

  update(dt, game) {
    super.update(dt, game);
    if (this.exploded) return;
    if (!this.armed) {
      this.armT -= dt;
      if (this.armT <= 0) {
        this.armed = true;
        spawnFloatingText(game, this.x, this.y - 10, 'READY!', '#ff4');
      }
    } else {
      for (const z of game.zombies) {
        if (z.row !== this.row || z.state === 'dying') continue;
        if (Math.abs(z.x - this.x) < 35) {
          this.detonate(game);
          return;
        }
      }
    }
  }

  detonate(game) {
    this.exploded = true;
    play('explode');
    spawnExplosion(game, this.x, this.y - 5);
    for (const z of game.zombies) {
      if (z.state === 'dying') continue;
      if (Math.abs(z.row - this.row) <= EXPLOSION_RADIUS_COLS &&
          Math.abs((z.x - this.x) / 80) <= EXPLOSION_RADIUS_COLS + 0.5) {
        z.hp = -9999;
        z.accessoryHp = 0;
      }
    }
    this.isDead = true;
  }

  draw(ctx) {
    if (!this.armed) {
      // buried: only top edge of potato visible, label
      ctx.fillStyle = '#a87c3a';
      ctx.beginPath();
      ctx.ellipse(0, 8, 16, 5, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = 'rgba(0,0,0,0.7)';
      ctx.fillRect(-32, -10, 64, 16);
      ctx.fillStyle = '#fff';
      ctx.font = 'bold 9px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('准备中', 0, 1);
    } else {
      // armed: full potato + blinking red button
      const grad = ctx.createRadialGradient(-4, -4, 3, 0, 0, 22);
      grad.addColorStop(0, '#d4a070');
      grad.addColorStop(1, '#7a5020');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.ellipse(0, 0, 24, 16, 0, 0, Math.PI * 2);
      ctx.fill();
      // dark spots
      ctx.fillStyle = '#5a3010';
      ctx.beginPath(); ctx.ellipse(-10, -3, 3, 2, 0, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.ellipse(8, 3, 3, 2, 0, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.ellipse(-2, 6, 2.5, 1.5, 0, 0, Math.PI * 2); ctx.fill();
      // button
      const blink = Math.sin(this.lifetime * 8) * 0.5 + 0.5;
      ctx.fillStyle = `rgb(${180 + blink * 75 | 0}, ${30 + blink * 30 | 0}, 30)`;
      ctx.beginPath(); ctx.arc(0, -10, 6, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = `rgba(255,255,255,${(0.2 + blink * 0.4).toFixed(2)})`;
      ctx.beginPath(); ctx.arc(-2, -12, 2, 0, Math.PI * 2); ctx.fill();
      // eyes
      ctx.fillStyle = '#000';
      ctx.beginPath(); ctx.arc(-7, 0, 1.5, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(5, 0, 1.5, 0, Math.PI * 2); ctx.fill();
    }
  }
}

const PLANT_CTORS = {
  sunflower: Sunflower,
  peashooter: Peashooter,
  wallnut: Wallnut,
  cherrybomb: CherryBomb,
  snowpea: SnowPea,
  potatomine: PotatoMine,
};
function createPlant(id, col, row) {
  const Ctor = PLANT_CTORS[id];
  if (!Ctor) throw new Error('Unknown plant: ' + id);
  return new Ctor(col, row);
}
function getPlantCtor(id) {
  return PLANT_CTORS[id];
}

